from urllib.parse import urlparse

import requests

MAX_FETCH_BYTES = int(os.environ.get("MAX_FETCH_BYTES", "65536"))
TIMEOUT_SECONDS = float(os.environ.get("TIMEOUT_SECONDS", "2.0"))
ALLOWED_SCHEMES = {"http", "https"}
ALLOWED_HOSTS = set(h.strip().lower() for h in os.environ.get("ALLOWED_HOSTS", "").split(",") if h.strip())
REQUIRE_ALLOWED_HOSTS = os.environ.get("REQUIRE_ALLOWED_HOSTS", "false").lower() in {"1", "true", "yes"}
MAX_URL_LENGTH = int(os.environ.get("MAX_URL_LENGTH", "2048"))
HEADER_NAME = "x-enrich-url"

_session = requests.Session()
_session.headers.update({"User-Agent": "LambdaEdgeEnricher/1.0"})


def _get_header_value(headers, name):
    key = name.lower()
    value = headers.get(key)
    if not value:
        return None
    if isinstance(value, list):
        if not value:
            return None
        value = value[0]
    if isinstance(value, dict):
        return value.get("value")
    if isinstance(value, str):
        return value
    return None


def _set_header(headers, name, value):
    headers[name.lower()] = [{"key": name, "value": value}]


def _sanitize_url(url):
    if not url:
        return None
    url = url.strip()
    if len(url) > MAX_URL_LENGTH:
        return None
    parsed = urlparse(url)
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        return None
    if not parsed.hostname:
        return None
    host = parsed.hostname.lower()
    if REQUIRE_ALLOWED_HOSTS and host not in ALLOWED_HOSTS:
        return None
    if parsed.username or parsed.password:
        return None
    return url


def _fetch_context(url):
    try:
        resp = _session.get(url, timeout=TIMEOUT_SECONDS, stream=True, allow_redirects=False)
        content = b""
        for chunk in resp.iter_content(chunk_size=8192):
            if not chunk:
                continue
            content += chunk
            if len(content) >= MAX_FETCH_BYTES:
                content = content[:MAX_FETCH_BYTES]
                break
        text = content.decode(resp.encoding or "utf-8", errors="replace")
        return {
            "status_code": resp.status_code,
            "content_type": resp.headers.get("Content-Type", ""),
            "body": text,
            "url": url,
        }
    except Exception as e:
        return {
            "error": str(e),
            "url": url,
        }


def lambda_handler(event, context):
    record = event["Records"][0]["cf"]
    request = record["request"]
    headers = request.get("headers", {})

    enrich_url = _get_header_value(headers, HEADER_NAME)
    sanitized_url = _sanitize_url(enrich_url)

